/// Errors that can occur during GraphQL operations
///
/// These errors are compatible with async-graphql error handling and can be
/// converted to structured HTTP responses matching the project's error fixtures.
public enum GraphQLError: Swift.Error {
    /// Error during schema execution
    ///
    /// Occurs when the GraphQL executor encounters a runtime error during query execution.
    case executionError(message: String, field0: String)
    /// Error during schema building
    ///
    /// Occurs when schema construction fails due to invalid definitions or conflicts.
    case schemaBuildError(message: String, field0: String)
    /// Error during request handling
    ///
    /// Occurs when the HTTP request cannot be properly handled or parsed.
    case requestHandlingError(message: String, field0: String)
    /// Serialization error
    ///
    /// Occurs during JSON serialization/deserialization of GraphQL values.
    case serializationError(message: String, field0: String)
    /// JSON parsing error
    ///
    /// Occurs when JSON input cannot be parsed.
    case jsonError(message: String, field0: String)
    /// GraphQL validation error
    ///
    /// Occurs when a GraphQL query fails schema validation.
    case validationError(message: String, field0: String)
    /// GraphQL parse error
    ///
    /// Occurs when the GraphQL query string cannot be parsed.
    case parseError(message: String, field0: String)
    /// Authentication error
    ///
    /// Occurs when request authentication fails.
    case authenticationError(message: String, field0: String)
    /// Authorization error
    ///
    /// Occurs when user lacks required permissions.
    case authorizationError(message: String, field0: String)
    /// Not found error
    ///
    /// Occurs when a requested resource is not found.
    case notFound(message: String, field0: String)
    /// Rate limit error
    ///
    /// Occurs when rate limit is exceeded.
    case rateLimitExceeded(message: String, field0: String)
    /// Invalid input error with validation details
    ///
    /// Occurs during input validation with detailed error information.
    case invalidInput(message: String)
    /// Query complexity limit exceeded
    ///
    /// Occurs when a GraphQL query exceeds the configured complexity limit.
    case complexityLimitExceeded
    /// Query depth limit exceeded
    ///
    /// Occurs when a GraphQL query exceeds the configured depth limit.
    case depthLimitExceeded
    /// Internal server error
    ///
    /// Occurs when an unexpected internal error happens.
    case internalError(message: String, field0: String)
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

extension GraphQLError {
    public var statusCode: UInt16 {
        switch self {
        case .executionError(message: _, field0: _): return 0
        case .schemaBuildError(message: _, field0: _): return 0
        case .requestHandlingError(message: _, field0: _): return 0
        case .serializationError(message: _, field0: _): return 0
        case .jsonError(message: _, field0: _): return 0
        case .validationError(message: _, field0: _): return 0
        case .parseError(message: _, field0: _): return 0
        case .authenticationError(message: _, field0: _): return 0
        case .authorizationError(message: _, field0: _): return 0
        case .notFound(message: _, field0: _): return 0
        case .rateLimitExceeded(message: _, field0: _): return 0
        case .invalidInput(message: _): return 0
        case .complexityLimitExceeded: return 0
        case .depthLimitExceeded: return 0
        case .internalError(message: _, field0: _): return 0
        case .validation(message: _, source: _): return 0
        }
    }
    public var isTransient: Bool {
        switch self {
        case .executionError(message: _, field0: _): return false
        case .schemaBuildError(message: _, field0: _): return false
        case .requestHandlingError(message: _, field0: _): return false
        case .serializationError(message: _, field0: _): return false
        case .jsonError(message: _, field0: _): return false
        case .validationError(message: _, field0: _): return false
        case .parseError(message: _, field0: _): return false
        case .authenticationError(message: _, field0: _): return false
        case .authorizationError(message: _, field0: _): return false
        case .notFound(message: _, field0: _): return false
        case .rateLimitExceeded(message: _, field0: _): return false
        case .invalidInput(message: _): return false
        case .complexityLimitExceeded: return false
        case .depthLimitExceeded: return false
        case .internalError(message: _, field0: _): return false
        case .validation(message: _, source: _): return false
        }
    }
    public var errorType: String {
        switch self {
        case .executionError(message: _, field0: _): return ""
        case .schemaBuildError(message: _, field0: _): return ""
        case .requestHandlingError(message: _, field0: _): return ""
        case .serializationError(message: _, field0: _): return ""
        case .jsonError(message: _, field0: _): return ""
        case .validationError(message: _, field0: _): return ""
        case .parseError(message: _, field0: _): return ""
        case .authenticationError(message: _, field0: _): return ""
        case .authorizationError(message: _, field0: _): return ""
        case .notFound(message: _, field0: _): return ""
        case .rateLimitExceeded(message: _, field0: _): return ""
        case .invalidInput(message: _): return ""
        case .complexityLimitExceeded: return ""
        case .depthLimitExceeded: return ""
        case .internalError(message: _, field0: _): return ""
        case .validation(message: _, source: _): return ""
        }
    }
}

